function projectDetail({
  projectId,
  projectKey,
  projectName,
  contentTypeId,
  fieldId,
  entryId,
  variantId,
  mappingId,
}: {
  projectId: number;
  projectKey: string;
  projectName: string;
  contentTypeId: number;
  fieldId: number;
  entryId: number;
  variantId: number;
  mappingId?: number;
}) {
  const authoringSha256 = (projectKey === 'project-b' ? 'b' : 'a').repeat(64);
  return {
    project: {
      id: projectId,
      entityVersion: 0,
      audit: cmsAudit,
      projectKey,
      name: projectName,
      description: null,
      enabled: true,
      repository: { id: projectId + 10, name: `${projectName} repository` },
      asset: { id: projectId + 20, path: `cms/${projectKey}` },
      sourceLocale: 'en',
      deliveryHint: 'BLOB_CDN',
    },
    authoringSha256,
    contentTypes: [
      {
        id: contentTypeId,
        entityVersion: 0,
        audit: cmsAudit,
        projectId,
        typeKey: 'email',
        name: `${projectName} email`,
        description: null,
        schemaVersion: 1,
        metadataSchemaJson: null,
        fields: [
          {
            id: fieldId,
            entityVersion: 0,
            audit: cmsAudit,
            contentTypeId,
            fieldKey: 'header',
            name: `${projectName} header`,
            description: null,
            fieldType: 'TEXT' as const,
            localizable: true,
            required: true,
            sortOrder: 0,
          },
        ],
      },
    ],
    entries: [
      {
        id: entryId,
        entityVersion: 0,
        audit: cmsAudit,
        projectId,
        contentTypeId,
        entryKey: 'welcome',
        name: `${projectName} welcome`,
        description: null,
        status: 'DRAFT' as const,
        metadataJson: null,
        variants: [
          {
            id: variantId,
            entityVersion: 0,
            audit: cmsAudit,
            entryId,
            variantKey: 'default',
            name: `${projectName} default`,
            candidateGroupKey: null,
            status: 'CONTROL' as const,
            metadataJson: null,
            sortOrder: 0,
            fieldMappings:
              mappingId == null
                ? []
                : [
                    {
                      id: mappingId,
                      entityVersion: 3,
                      audit: cmsAudit,
                      variantId,
                      fieldId,
                      fieldKey: 'header',
                      tmTextUnitId: mappingId + 100,
                      stringId: `cms.${projectKey}.welcome.default.header`,
                      sourceContent: 'Hello',
                      sourceComment: 'Shown in welcome email header',
                    },
                  ],
          },
        ],
      },
    ],
    publishSnapshots: [],
    hasMorePublishSnapshots: false,
    nextBeforePublishSnapshotVersion: null,
  };
}

function renderPage({
  initialEntries = ['/settings/system/content-cms'],
  initialIndex,
}: {
  initialEntries?: string[];
  initialIndex?: number;
} = {}) {
  const queryClient = new QueryClient({
    defaultOptions: {
      mutations: { retry: false },
      queries: { retry: false },
    },
  });
  const router = createMemoryRouter(
    [
      {
        path: '/settings/system/content-cms',
        element: (
          <>
            <NavLink to="/repositories">App repositories</NavLink>
            <AdminContentCmsPage />
          </>
        ),
      },
      {
        path: '/settings/system/content-cms/admin',
        element: (
          <>
            <NavLink to="/repositories">App repositories</NavLink>
            <AdminContentCmsPage mode="admin" />
          </>
        ),
      },
      { path: '/repositories', element: <div>Repositories</div> },
      { path: '/settings/system', element: <div>Settings system</div> },
    ],
    { initialEntries, initialIndex },
  );
  activeRouter = router;

  return {
    ...render(
      <QueryClientProvider client={queryClient}>
        <RouterProvider router={router} />
      </QueryClientProvider>,
    ),
    queryClient,
    router,
  };
}

