function copyFieldForm(name: string) {
  const fieldCard = screen
    .getByRole('heading', { name })
    .closest('.content-cms-admin-page__field-outline-card');
  if (!(fieldCard instanceof HTMLElement)) {
    throw new Error(`Copy field card not found: ${name}`);
  }
  if (!fieldCard.classList.contains('is-active')) {
    return fieldCard;
  }
  const openTranslationEditor = () => {
    const translationEditorTrigger = within(fieldCard).queryByRole('button', {
      name: /^(Write|Review|Open) .+ translation$/,
    });
    if (translationEditorTrigger == null) {
      return false;
    }
    fireEvent.click(translationEditorTrigger);
    return true;
  };
  if (!openTranslationEditor()) {
    const observer = new MutationObserver(() => {
      if (openTranslationEditor()) {
        observer.disconnect();
      }
    });
    observer.observe(fieldCard, { childList: true, subtree: true });
  }
  return fieldCard;
}

