function openDisclosureIfClosed(label: string) {
  if (label === 'Admin tools') {
    openAdminToolsPage();
    return;
  }
  if (
    label === 'Structure and mappings' ||
    label === 'Advanced maintenance' ||
    label === 'Technical release details'
  ) {
    openAdminToolsPage();
  }
  if (
    label === 'Repair copy structure' ||
    label === 'Add experiment candidate' ||
    label === 'Repair Mojito links'
  ) {
    openDisclosureIfClosed('Structure and mappings');
  }
  if (
    label === 'Rename or disable copy collection' ||
    label === 'Edit copy structure' ||
    label === 'Debug raw records'
  ) {
    openDisclosureIfClosed('Advanced maintenance');
  }
  const disclosure = screen.getByRole('button', { name: new RegExp(`^${label}`) });
  if (disclosure.getAttribute('aria-expanded') !== 'true') {
    fireEvent.click(disclosure);
  }
}

function pressMaintenanceAction(label: string) {
  const action = maintenanceAction(label);
  if (action.getAttribute('aria-pressed') !== 'true') {
    fireEvent.click(action);
  }
}

function maintenanceAction(label: string) {
  const action = screen
    .getAllByRole('button', { name: label })
    .find((button) => button.hasAttribute('aria-pressed'));
  if (action == null) {
    throw new Error(`Maintenance action not found: ${label}`);
  }
  return action;
}

