  it('reopens requested translations after the inline editor readiness retry succeeds', async () => {
    const user = userEvent.setup();
    let resolveRefresh: (() => void) | null = null;
    mocks.fetchCmsProject.mockResolvedValue(mappedProjectA);
    mocks.fetchCmsEntryCompleteness
      .mockRejectedValueOnce(new Error('failed'))
      .mockImplementationOnce(
        () =>
          new Promise((resolve) => {
            resolveRefresh = () => resolve(projectANeedsTranslationCompleteness);
          }),
      );

    renderPage({
      initialEntries: [
        '/settings/system/content-cms?projectId=1&entryId=301&fieldId=201&locale=fr-FR',
      ],
    });

    await screen.findAllByText('Project A header');
    const headlineField = copyFieldForm('Project A header');
    expect(
      await within(headlineField).findByText('French (France) translation could not open.'),
    ).toBeVisible();
    expect(within(headlineField).getByText('Try again to open it.')).toBeVisible();
    expect(within(headlineField).queryByText('Translation')).not.toBeInTheDocument();
    expect(
      within(headlineField).queryByLabelText('Project A header translation status'),
    ).not.toBeInTheDocument();
    const tryAgain = await within(headlineField).findByRole('button', { name: 'Try again' });
    await waitFor(() => expect(tryAgain).toHaveFocus());

    await user.click(tryAgain);

    expect(await within(headlineField).findByRole('button', { name: 'Opening...' })).toBeDisabled();

    act(() => {
      if (resolveRefresh == null) {
        throw new Error('Expected readiness refresh resolver');
      }
      resolveRefresh();
    });

    const translation = await within(headlineField).findByLabelText('French (France) translation');
    await waitFor(() => expect(translation).toHaveFocus());
  });

