  it('opens a scoped language chooser when multiple configured translations remain after removal', async () => {
    const user = userEvent.setup();
    const japaneseLocaleLabel = resolveLocaleDisplayName('ja-JP');
    mocks.fetchCmsProject.mockResolvedValue(mappedProjectA);
    mocks.fetchCmsEntryCompleteness.mockResolvedValue(
      projectAWithMultipleEditableAlternatesCompleteness,
    );
    mocks.searchTextUnits.mockResolvedValue([
      projectATargetTextUnit,
      {
        ...projectATargetTextUnit,
        localeId: 1002,
        target: 'Willkommen',
        targetLocale: 'de-DE',
        status: 'APPROVED',
      },
    ]);

    renderPage({
      initialEntries: [
        '/settings/system/content-cms?projectId=1&entryId=301&fieldId=201&locale=ja-JP',
      ],
    });

    await screen.findAllByText('Project A header');
    const headlineField = copyFieldForm('Project A header');
    expect(
      await within(headlineField).findByText(`${japaneseLocaleLabel} is not set up for this copy.`),
    ).toBeVisible();
    expect(
      within(headlineField).getByText(
        `Add ${japaneseLocaleLabel} again, or choose another translation language.`,
      ),
    ).toBeVisible();
    expect(
      within(headlineField).getByRole('button', { name: `Add ${japaneseLocaleLabel}` }),
    ).toBeVisible();
    expect(mocks.fetchCmsFieldTranslation).not.toHaveBeenCalledWith(expect.anything(), 'ja-JP');
    expect(mocks.fetchCmsFieldTranslation).not.toHaveBeenCalledWith(expect.anything(), 'fr-FR');
    expect(
      within(headlineField).queryByRole('button', {
        name: 'Continue with French (France)',
      }),
    ).toBeNull();
    expect(within(headlineField).queryByRole('button', { name: 'Switch language' })).toBeNull();
    expect(
      within(headlineField).queryByRole('button', { name: 'Hide translation editor' }),
    ).toBeNull();
    const chooseAnotherLanguage = within(headlineField).getByRole('button', {
      name: 'Choose another language',
    });
    expect(chooseAnotherLanguage).toHaveClass('settings-button--ghost');

    await user.click(chooseAnotherLanguage);

    const frenchLocale = within(headlineField).getByRole('button', {
      name: 'French (France) Needs translation',
    });
    await waitFor(() => expect(frenchLocale).toHaveFocus());
    expect(
      within(headlineField).getByRole('button', {
        name: 'Hide languages',
      }),
    ).toBeVisible();

    await user.click(
      within(headlineField).getByRole('button', {
        name: 'German (Germany) Approved',
      }),
    );

    await waitFor(() =>
      expect(mocks.fetchCmsFieldTranslation).toHaveBeenCalledWith(
        expect.objectContaining({ id: 501, tmTextUnitId: 601 }),
        'de-DE',
      ),
    );
    const germanTranslation = await within(headlineField).findByLabelText(
      'German (Germany) translation',
    );
    await waitFor(() => expect(germanTranslation).toHaveFocus());
    expect(
      within(headlineField).queryByText(`${japaneseLocaleLabel} is not set up for this copy.`),
    ).not.toBeInTheDocument();
  });

