  it('retries refreshed copy-detail conflicts with the latest block version', async () => {
    const user = userEvent.setup();
    mocks.fetchCmsProject.mockImplementation(() =>
      Promise.resolve(
        mocks.updateCmsEntry.mock.calls.length === 0
          ? mappedProjectA
          : refreshedBlockDetailsProjectA,
      ),
    );
    mocks.isCmsConflictError.mockReturnValue(true);
    mocks.updateCmsEntry
      .mockRejectedValueOnce(new Error('CMS entry changed'))
      .mockResolvedValueOnce(refreshedBlockDetailsProjectA);

    renderPage();

    await screen.findByText('Project A header');
    await openSavedItemDetails(user);
    const blockDetails = copyBlockDetails();
    await user.type(within(blockDetails).getByLabelText('Content item name'), ' revised');
    await user.type(
      within(blockDetails).getByLabelText('Where this item appears'),
      'Shown after signup',
    );
    await user.click(within(blockDetails).getByRole('button', { name: 'Save copy details' }));

    await waitFor(() =>
      expect(mocks.updateCmsEntry).toHaveBeenNthCalledWith(1, 301, {
        description: 'Shown after signup',
        expectedVersion: 0,
        metadataJson: null,
        name: 'Project A welcome revised',
        status: 'DRAFT',
      }),
    );
    expect(await within(blockDetails).findByText('Saved elsewhere')).toBeVisible();
    expect(
      within(blockDetails).getByText('Saved copy details changed while you were editing.'),
    ).toBeVisible();
    expect(within(blockDetails).getByText('Project A welcome from another editor')).toBeVisible();
    expect(within(blockDetails).getByText('Project A welcome revised')).toBeVisible();
    expect(within(blockDetails).getByText('Signup confirmation from another editor')).toBeVisible();
    expect(within(blockDetails).getByText('Shown after signup')).toBeVisible();

    await user.click(within(blockDetails).getByRole('button', { name: 'Save copy details' }));

    await waitFor(() =>
      expect(mocks.updateCmsEntry).toHaveBeenNthCalledWith(2, 301, {
        description: 'Shown after signup',
        expectedVersion: 1,
        metadataJson: null,
        name: 'Project A welcome revised',
        status: 'DRAFT',
      }),
    );
  });

