  it('refreshes conflicting inline translation reconnects before retrying', async () => {
    const user = userEvent.setup();
    const readyMappedProjectWithCta = {
      ...mappedProjectWithCta,
      entries: mappedProjectWithCta.entries.map((entry) => ({
        ...entry,
        status: 'READY' as const,
      })),
    };
    const refreshedReadyMappedProjectWithCta = {
      ...readyMappedProjectWithCta,
      entries: readyMappedProjectWithCta.entries.map((entry) => ({
        ...entry,
        variants: entry.variants.map((variant) => ({
          ...variant,
          fieldMappings: variant.fieldMappings.map((mapping) =>
            mapping.fieldId === 211
              ? {
                  ...mapping,
                  entityVersion: mapping.entityVersion + 1,
                  sourceContent: 'Start now refreshed',
                  sourceComment: 'Primary action label refreshed',
                }
              : mapping,
          ),
        })),
      })),
    };
    const projectAWithCtaProjectCompleteness = {
      ...projectACompleteness,
      locales: projectAWithCtaCompleteness.locales,
      entries: [projectAWithCtaCompleteness],
      complete: false,
    };
    let targetAvailable = false;
    mocks.fetchCmsProject.mockImplementation(() =>
      Promise.resolve(
        mocks.upsertCmsFieldMapping.mock.calls.length === 0
          ? readyMappedProjectWithCta
          : refreshedReadyMappedProjectWithCta,
      ),
    );
    mocks.fetchCmsProjectCompleteness.mockResolvedValue(projectAWithCtaProjectCompleteness);
    mocks.fetchCmsEntryCompleteness.mockResolvedValue(projectAWithCtaCompleteness);
    mocks.isCmsConflictError.mockReturnValue(true);
    mocks.upsertCmsFieldMapping
      .mockRejectedValueOnce(new Error('CMS field mapping changed'))
      .mockResolvedValueOnce(refreshedReadyMappedProjectWithCta);
    mocks.searchTextUnits.mockImplementation(
      ({
        localeTags = [],
        tmTextUnitIds = [],
      }: {
        localeTags?: string[];
        tmTextUnitIds?: number[];
      }) =>
        Promise.resolve(
          targetAvailable
            ? [
                {
                  ...projectATargetTextUnit,
                  tmTextUnitId: tmTextUnitIds[0] ?? projectATargetTextUnit.tmTextUnitId,
                  targetLocale: localeTags[0] ?? projectATargetTextUnit.targetLocale,
                },
              ]
            : [],
        ),
    );
    const { router } = renderPage();

    await screen.findAllByText('Project A header');
    openPublishingIfClosed();
    await prepareReleaseForTest(user);

    const blockers = screen.getByRole('group', { name: 'Content items needing work' });
    await user.click(
      within(blockers).getByRole('button', {
        name: 'Write French (France) translation in CTA label for Project A welcome',
      }),
    );

    const ctaField = screen
      .getByRole('heading', { name: 'CTA label' })
      .closest('.content-cms-admin-page__field-outline-card');
    if (!(ctaField instanceof HTMLElement)) {
      throw new Error('CTA field not found');
    }
    await within(ctaField).findByText('French (France) translation is unavailable.');
    await user.click(within(ctaField).getByRole('button', { name: 'Reconnect French (France)' }));

    expect(
      await within(ctaField).findByText('French (France) translation could not reconnect.'),
    ).toBeVisible();
    expect(
      within(ctaField).getByText(
        'Saved copy changed while reconnecting French (France). Review the refreshed source copy, then reconnect French (France) again.',
      ),
    ).toBeVisible();
    await waitFor(() => expect(mocks.fetchCmsProject).toHaveBeenCalledTimes(2));
    expect(within(ctaField).getByLabelText('CTA label source copy')).toHaveValue(
      'Start now refreshed',
    );
    expect(within(ctaField).getByLabelText('CTA label translator note')).toHaveValue(
      'Primary action label refreshed',
    );
    const reconnectAgain = within(ctaField).getByRole('button', {
      name: 'Reconnect French (France) again',
    });
    await waitFor(() => expect(reconnectAgain).toHaveFocus());
    expect(
      screen.queryByText(
        'Could not reconnect French (France). Try again. If it keeps failing, ask an admin to check this field.',
      ),
    ).not.toBeInTheDocument();
    expect(router.state.location.pathname).toBe('/settings/system/content-cms');
    expect(router.state.location.search).toBe('');
    expect(screen.queryByRole('heading', { name: 'Admin tools' })).not.toBeInTheDocument();

    targetAvailable = true;
    await user.click(reconnectAgain);

    await waitFor(() =>
      expect(mocks.upsertCmsFieldMapping).toHaveBeenNthCalledWith(2, 401, {
        expectedVersion: 4,
        fieldId: 211,
        sourceComment: 'Primary action label refreshed',
        sourceContent: 'Start now refreshed',
        stringId: null,
        tmTextUnitId: null,
      }),
    );
    const ctaTranslation = await within(ctaField).findByLabelText('French (France) translation');
    await waitFor(() => expect(ctaTranslation).toHaveFocus());
  });

