  it('keeps failed release language add-back local before returning through current release truth', async () => {
    const user = userEvent.setup();
    const readyLocale = (localeTag: string, totalFields = 1) => ({
      localeTag,
      totalFields,
      approvedFields: totalFields,
      missingFields: 0,
      reviewNeededFields: 0,
      translationNeededFields: 0,
      complete: true,
    });
    const blockedLocale = (localeTag: string) => ({
      localeTag,
      totalFields: 1,
      approvedFields: 0,
      missingFields: 0,
      reviewNeededFields: 0,
      translationNeededFields: 1,
      complete: false,
    });
    const readyMappedProjectWithCta = {
      ...mappedProjectWithCta,
      entries: mappedProjectWithCta.entries.map((entry) => ({
        ...entry,
        status: 'READY' as const,
      })),
    };
    const projectAWithCtaJapaneseBlockedCompleteness = {
      ...projectAWithCtaMultipleEditableAlternatesCompleteness,
      locales: [
        readyLocale('en', 2),
        readyLocale('fr-FR', 2),
        readyLocale('de-DE', 2),
        {
          localeTag: 'ja-JP',
          totalFields: 2,
          approvedFields: 1,
          missingFields: 0,
          reviewNeededFields: 0,
          translationNeededFields: 1,
          complete: false,
        },
      ],
      fields: [
        {
          ...projectAWithCtaMultipleEditableAlternatesCompleteness.fields[0],
          locales: [
            readyLocale('en'),
            readyLocale('fr-FR'),
            readyLocale('de-DE'),
            readyLocale('ja-JP'),
          ],
        },
        {
          ...projectAWithCtaMultipleEditableAlternatesCompleteness.fields[1],
          locales: [
            readyLocale('en'),
            readyLocale('fr-FR'),
            readyLocale('de-DE'),
            blockedLocale('ja-JP'),
          ],
        },
      ],
    };
    const projectAWithCtaJapaneseBlockedProjectCompleteness = {
      ...projectACompleteness,
      localeTags: ['en', 'fr-FR', 'de-DE', 'ja-JP'],
      locales: projectAWithCtaJapaneseBlockedCompleteness.locales,
      entries: [projectAWithCtaJapaneseBlockedCompleteness],
      complete: false,
    };
    const projectAWithCtaMultipleEditableAlternatesProjectCompleteness = {
      ...projectACompleteness,
      localeTags: ['en', 'fr-FR', 'de-DE'],
      locales: projectAWithCtaMultipleEditableAlternatesCompleteness.locales,
      entries: [projectAWithCtaMultipleEditableAlternatesCompleteness],
      complete: false,
    };
    mocks.fetchCmsProject.mockResolvedValue(readyMappedProjectWithCta);
    mocks.fetchCmsProjectCompleteness
      .mockResolvedValueOnce(projectAWithCtaJapaneseBlockedProjectCompleteness)
      .mockResolvedValue(projectAWithCtaMultipleEditableAlternatesProjectCompleteness);
    mocks.fetchCmsEntryCompleteness.mockResolvedValue(
      projectAWithCtaMultipleEditableAlternatesCompleteness,
    );
    mocks.addCmsProjectTargetLocales.mockRejectedValueOnce(
      new Error('Failed to update CMS repository locales'),
    );

    renderPage();

    await screen.findAllByText('Project A header');
    openPublishingIfClosed();
    await prepareReleaseForTest(user);

    const blockers = screen.getByRole('group', { name: 'Content items needing work' });
    await user.click(
      within(blockers).getByRole('button', {
        name: 'Write Japanese (Japan) translation in CTA label for Project A welcome',
      }),
    );

    const ctaField = screen
      .getByRole('heading', { name: 'CTA label' })
      .closest('.content-cms-admin-page__field-outline-card');
    if (!(ctaField instanceof HTMLElement)) {
      throw new Error('CTA field not found');
    }
    const addJapanese = await within(ctaField).findByRole('button', {
      name: 'Add Japanese (Japan)',
    });
    await waitFor(() => expect(addJapanese).toHaveFocus());

    await user.click(addJapanese);

    await waitFor(() =>
      expect(mocks.addCmsProjectTargetLocales).toHaveBeenCalledWith(projectA.project.id, ['ja-JP']),
    );
    expect(await within(ctaField).findByText('Translation languages did not save')).toBeVisible();
    expect(
      within(ctaField).getByText(
        'Could not add translation languages. Try again. If it keeps failing, ask an admin to check language setup.',
      ),
    ).toBeVisible();
    expect(addJapanese).toBeEnabled();
    expect(within(ctaField).queryByLabelText('Japanese (Japan) translation')).toBeNull();
    expect(within(ctaField).getByRole('button', { name: 'Return to release' })).toBeVisible();

    const completenessCallsBeforeReturn = mocks.fetchCmsProjectCompleteness.mock.calls.length;
    await user.click(within(ctaField).getByRole('button', { name: 'Return to release' }));

    expect(document.getElementById('content-cms-release-panel')).toHaveFocus();
    await waitFor(() =>
      expect(mocks.fetchCmsProjectCompleteness.mock.calls.length).toBeGreaterThan(
        completenessCallsBeforeReturn,
      ),
    );
    await waitFor(() =>
      expect(
        releasePanel().queryByText('Japanese (Japan) needs translation before release.'),
      ).not.toBeInTheDocument(),
    );
    const refreshedBlockers = releasePanel().getByRole('group', {
      name: 'Content items needing work',
    });
    const refreshedCtaBlocker = within(refreshedBlockers).getByRole('button', {
      name: 'Write French (France) translation in CTA label for Project A welcome',
    });
    expect(
      within(refreshedCtaBlocker).getByText('French (France) needs translation before release.'),
    ).toBeVisible();
    expect(refreshedCtaBlocker).toBeVisible();
  });

